// Validate all fields
const data = $input.last().json;
const errors = [];

// Required fields check
const required = ['Project Name', 'Project Tagline', 'Project Description', 'Discord ID', 'Project Website', 'Project Logo'];
for (const field of required) {
  if (!data[field] || data[field].trim() === '') {
    errors.push(`Missing required field: ${field}`);
  }
}

// URL validation helper
function isValidUrl(string) {
  try {
    new URL(string);
    return true;
  } catch (_) {
    return false;
  }
}

// Validate main href
if (data.href && !isValidUrl(data.href)) {
  errors.push('Invalid project URL (href)');
}

// Validate mediaSrc
if (data.mediaSrc && !isValidUrl(data.mediaSrc)) {
  errors.push('Invalid media source URL');
}

// Validate logo
if (data.logo && !isValidUrl(data.logo)) {
  errors.push('Invalid logo URL');
}

// Validate links object
if (data.links) {
  try {
    const links = typeof data.links === 'string' ? JSON.parse(data.links) : data.links;
    for (const [key, value] of Object.entries(links)) {
      if (value && !isValidUrl(value)) {
        errors.push(`Invalid ${key} link`);
      }
    }
  } catch (e) {
    errors.push('Invalid links format');
  }
}

return {
  json: {
    ...data,
    isValid: errors.length === 0,
    errors: errors,
    errorMessage: errors.join(', ')
  }
};

