// Transform Google Sheets data to showcase format
const data = $input.first().json;

const submissionId = data['Timestamp'].toString().replace(/[^0-9]/g, '');

// -----------------------------
// Parse tags
// -----------------------------
const categoryTags = data['Project Category']
  ? data['Project Category'].split(',').map(t => t.trim())
  : [];

const productTags = data['Livepeer Platforms Used']
  ? data['Livepeer Platforms Used'].split(',').map(t => t.trim())
  : [];

const raw = (data['Media File Type'] || '').toString().toLowerCase();

const mediaType =
  raw === 'video / gif' || raw === 'video'
    ? 'video'
    : 'image';

// -----------------------------
// Links
// -----------------------------
const links = [];
const urlFields = {
  'Github URL': 'github',
  'X / Twitter URL': 'twitter',
  'Discord Invite URL': 'discord',
  'Youtube Channel URL': 'youtube',
  'Telegram URL': 'telegram',
  'Instagram URL': 'instagram',
  'Blog Site URL': 'blog',
  'LinkedIn URL': 'linkedin',
  'Whatsapp URL': 'whatsapp',
  'Reddit URL': 'reddit',
  'Bluesky URL': 'bluesky',
  'Twitch URL': 'twitch',
  'Other URL? ': 'other',
  'Project Website': 'website',
  'Email Contact (user facing)': 'email'
};

for (const [fieldName, linkKey] of Object.entries(urlFields)) {
  if (data[fieldName] && data[fieldName].trim()) {
    links.push({ [linkKey]: data[fieldName].trim() });
  }
}


// -----------------------------
// Showcase object
// -----------------------------
const showcaseObject = {
  title: data['Project Name'],
  subtitle: data['Project Tagline'],
  href: data['Project Website'],
  mediaSrc: data['Hero Media File'],
  mediaType, 
  logo: data['Project Logo'],
  categoryTags,
  productTags,
  description:
    (data['Project Description'] || '') +
    ' ' +
    (data['How your project leverages Livepeer'] || ''),
  cta: data['Call to Action (CTA)'] || '',
  links
};

return {
  json: {
    ...data,
    submissionId,
    showcaseObject,
    showcaseFormatted: JSON.stringify(showcaseObject, null, 2),
    approved: 'no'
  }
};

