// Get SHA from GitHub
const sha = $('Get GitHub File').first().json.sha;

// Get all rows from sheet
const allRows = $('Get All Approved Submissions').all();

// Build showcase array from approved rows
const approvedRows = allRows.filter(item => item.json.approved === 'yes');
const showcaseArray = approvedRows.map(item => JSON.parse(item.json.showcaseJSX));

// Build GitHub file
const fileContent = `export const showcaseData = ${JSON.stringify(showcaseArray, null, 2)};\n`;
const encoded = Buffer.from(fileContent).toString('base64');

// Build Discord embeds for each approved project
const discordEmbeds = approvedRows.map(item => {
  const data = item.json;
  const categoryTags = JSON.parse(data.categoryTags);
  const productTags = JSON.parse(data.productTags);
  const links = JSON.parse(data.links);
  const email = $input.first().json.email;
  const discordId = $input.first().json.discordId;
  const editLink = $input.first().json.editLink;

  return {
    title: data.title,
    description: `${data.subtitle}\n\n${data.description}`,
    url: data.href,
    color: 5814783,
    fields: [
      {
        "name": "Submitter:",
        "value": `${email}, <@${discordId}>`,
        "inline": false
      },
      {
        name: "Categories",
        value: categoryTags.join(', '),
        inline: true
      },
      {
        name: "Products",
        value: productTags.join(', '),
        inline: true
      },
      {
        name: "Links",
        value: links.map(l => {
          const [k, v] = Object.entries(l)[0];
          if (k === 'email') return `✉️ **Email**: ${v}`;
          return `🔗 **${k.charAt(0).toUpperCase() + k.slice(1)}**: ${v}`;
        }).join('\n'),
        inline: false
      },
      {
        name: "Edit Response",
        value: `[Edit Form Here](${editLink})`,
        inline: false
      }
    ],
    thumbnail: {
      url: data.logo
    }
  };
});

return {
  json: {
    // For GitHub commit
    content: encoded,
    sha: sha,
    message: `Update showcase: ${approvedRows.length} approved projects`,

    // For Discord notification
    discordMessage: {
      content: `✅ **Showcase Updated!**\n\n${approvedRows.length} approved project(s) now live:`,
      embeds: discordEmbeds
    },

    recipient: $input.first().json.discordId
  }
};

